//! XML configuration parser with external entity support.
//!
//! WARNING: Resolving external entities can expose the application
//! to XXE-style vulnerabilities such as local file disclosure or SSRF.
//! Ensure inputs come from trusted sources or apply additional
//! sandboxing/validation before using in production.

use std::collections::HashMap;
use std::fs;
use std::io::Read;

use regex::Regex;
use xml::reader::{EventReader, XmlEvent};

pub type Config = HashMap<String, String>;

pub fn parse_config_with_external_entities<R: Read>(
    reader: R,
) -> Result<Config, Box<dyn std::error::Error>> {
    let mut config = HashMap::new();
    let mut entities: HashMap<String, String> = HashMap::new();

    let parser = EventReader::new(reader);

    let mut current_key: Option<String> = None;
    let mut in_setting = false;
    let mut buffer = String::new();

    for evt in parser {
        match evt? {
            XmlEvent::DocType(dtd) => {
                extract_entities(&dtd, &mut entities)?;
            }
            XmlEvent::StartElement { name, attributes, .. } => {
                if name.local_name == "setting" {
                    in_setting = true;
                    buffer.clear();
                    current_key = attributes
                        .iter()
                        .find(|a| a.name.local_name == "name")
                        .map(|a| a.value.clone());
                }
            }
            XmlEvent::Characters(text) | XmlEvent::CData(text) => {
                if in_setting {
                    buffer.push_str(&expand_entities(&text, &entities)?);
                }
            }
            XmlEvent::EndElement { name } => {
                if name.local_name == "setting" {
                    if let Some(key) = current_key.take() {
                        config.insert(key, buffer.trim().to_owned());
                    }
                    in_setting = false;
                    buffer.clear();
                }
            }
            _ => {}
        }
    }

    Ok(config)
}

fn extract_entities(
    dtd: &str,
    entities: &mut HashMap<String, String>,
) -> Result<(), Box<dyn std::error::Error>> {
    let re = Regex::new(r#"<!ENTITY\s+([A-Za-z0-9_.:-]+)\s+SYSTEM\s+"([^"]+)""#)?;
    for cap in re.captures_iter(dtd) {
        let name = cap.get(1).unwrap().as_str().to_string();
        let path = cap.get(2).unwrap().as_str();
        let content = fs::read_to_string(path)?;
        entities.insert(name, content);
    }
    Ok(())
}

fn expand_entities(
    text: &str,
    entities: &HashMap<String, String>,
) -> Result<String, Box<dyn std::error::Error>> {
    let mut out = String::new();
    let mut idx = 0;

    while let Some(amp) = text[idx..].find('&') {
        let amp = idx + amp;
        out.push_str(&text[idx..amp]);
        if let Some(semi) = text[amp..].find(';') {
            let semi = amp + semi;
            let name = &text[amp + 1..semi];
            if let Some(repl) = entities.get(name) {
                out.push_str(repl);
            } else {
                out.push_str(&text[amp..=semi]);
            }
            idx = semi + 1;
        } else {
            break;
        }
    }
    out.push_str(&text[idx..]);
    Ok(out)
}

