    use super::*;

    #[test]
    fn it_parses_settings_with_external_entity() {
        let xml = r#"
            <!DOCTYPE config [
              <!ENTITY common SYSTEM "tests/common.txt">
            ]>
            <config>
              <setting name="greeting">&common;</setting>
              <setting name="version">1.2.3</setting>
            </config>
        "#;

        // Prepare mock file for entity.
        fs::create_dir_all("tests").unwrap();
        fs::write("tests/common.txt", "hello world").unwrap();

        let cfg = parse_config_with_external_entities(xml.as_bytes()).unwrap();
        assert_eq!(cfg.get("greeting").unwrap(), "hello world");
        assert_eq!(cfg.get("version").unwrap(), "1.2.3");

        fs::remove_file("tests/common.txt").unwrap();
    }
